export type QuestionCluster='Self Assessment enquiries'|'HMRC compliance checks'|'VAT and PAYE enquiries'|'COP8 and COP9 investigations'|'Undeclared income and disclosures'|'HMRC penalties and appeals';
export type QuestionPage={slug:string;cluster:QuestionCluster;hub:string;question:string;short:string;description:string;answer:string;why:string[];steps:string[];records:string[];pitfalls:string[];faqs:[string,string][];sources:[string,string][]};

const saSources:[string,string][]=[['GOV.UK: Self Assessment tax returns','https://www.gov.uk/self-assessment-tax-returns'],['HMRC Self Assessment Legal Framework Manual','https://www.gov.uk/hmrc-internal-manuals/self-assessment-legal-framework']];
const checkSources:[string,string][]=[['GOV.UK: Tax compliance checks','https://www.gov.uk/tax-compliance-checks'],['HMRC compliance-check factsheets','https://www.gov.uk/government/collections/hm-revenue-and-customs-compliance-checks-factsheets']];
const vatSources:[string,string][]=[['GOV.UK: VAT record keeping','https://www.gov.uk/vat-record-keeping'],['GOV.UK: VAT visits and inspections','https://www.gov.uk/vat-visits-inspections'],['GOV.UK: PAYE and payroll','https://www.gov.uk/paye-for-employers']];
const copSources:[string,string][]=[['GOV.UK: Code of Practice 8','https://www.gov.uk/government/publications/code-of-practice-8-investigations'],['GOV.UK: Code of Practice 9','https://www.gov.uk/government/publications/code-of-practice-9-where-hmrc-suspects-fraud-cop-9']];
const disclosureSources:[string,string][]=[['GOV.UK: Tell HMRC about undeclared income','https://www.gov.uk/undeclared-income'],['GOV.UK: Make a voluntary disclosure','https://www.gov.uk/government/publications/hmrc-your-guide-to-making-a-disclosure/your-guide-to-making-a-disclosure']];
const appealSources:[string,string][]=[['GOV.UK: Disagree with a tax decision','https://www.gov.uk/tax-appeals'],['GOV.UK: Appeal to the tax tribunal','https://www.gov.uk/tax-tribunal']];

const q=(data:QuestionPage)=>data;
export const questions:QuestionPage[]=[
q({slug:'why-hmrc-opened-self-assessment-enquiry',cluster:'Self Assessment enquiries',hub:'self-assessment-enquiry',question:'Why has HMRC opened a Self Assessment enquiry?',short:'Why HMRC opens enquiries',description:'Understand why HMRC may open a Self Assessment enquiry, common risk indicators, what the letter means and the first steps to take.',answer:'HMRC can open an enquiry into a Self Assessment return within the statutory enquiry window without first proving that the return is wrong. Selection may follow risk analysis, third-party information, unusual figures or another compliance concern, but the notice itself does not establish an error or fraud.',why:['HMRC does not normally disclose the exact risk signal behind selection. Differences between returns and information from employers, banks, platforms or overseas authorities can prompt questions.','The opening notice should identify the return under enquiry. Separate a formal enquiry from an informal request or a discovery assessment because the powers, time limits and appeal position can differ.'],steps:['Record the notice date and response deadline','Download the filed return and computation','Identify every question and requested document','Tell the accountant or adviser who prepared the return','Prepare an evidence-led response without guessing'],records:['HMRC opening letter','Submitted return and computation','Source records for questioned entries','Earlier correspondence with HMRC'],pitfalls:['Assuming an enquiry proves wrongdoing','Sending an unsorted archive','Speculating about why HMRC selected the return'],faqs:[['Does HMRC need evidence before opening an enquiry?','Not necessarily where a valid enquiry is opened within the statutory window.'],['Does an enquiry mean fraud is suspected?','No. Many enquiries concern accuracy or supporting evidence rather than suspected fraud.']],sources:saSources}),
q({slug:'what-is-section-9a-enquiry',cluster:'Self Assessment enquiries',hub:'self-assessment-enquiry',question:'What is a Section 9A Self Assessment enquiry?',short:'Section 9A enquiries',description:'A clear UK guide to Section 9A TMA 1970 enquiries, enquiry notices, scope, deadlines, information requests and closure notices.',answer:'A Section 9A enquiry is HMRC’s statutory enquiry into a filed individual Self Assessment return under section 9A of the Taxes Management Act 1970. HMRC must give notice within the applicable enquiry window, and the enquiry normally ends with a closure notice.',why:['The enquiry can examine one entry or the return more widely. Expressions such as “aspect enquiry” and “full enquiry” describe practical scope but do not create separate statutory regimes.','The validity of the notice and its timing can matter. Amendments, late returns and returns delivered to the wrong office may affect the analysis, so use the exact dates and documents.'],steps:['Confirm the return and tax year named','Check when the return and any amendment were filed','Identify the statutory response required','Reconcile supporting schedules to the return','Obtain formal closure when the enquiry ends'],records:['Section 9A notice','Proof of filing','Return amendments','Working papers and tax computation'],pitfalls:['Confusing Section 9A with discovery','Treating an informal email as formal closure','Ignoring an information notice issued during the enquiry'],faqs:[['Can HMRC look at the whole return?','Potentially yes, depending on the scope and questions raised.'],['How does the enquiry end?','Normally through a closure notice stating HMRC’s conclusions and any amendment.']],sources:saSources}),
q({slug:'hmrc-self-assessment-enquiry-time-limit',cluster:'Self Assessment enquiries',hub:'self-assessment-enquiry',question:'How long does HMRC have to investigate a Self Assessment tax return?',short:'Self Assessment enquiry time limits',description:'Learn the normal HMRC Self Assessment enquiry window and why discovery assessment time limits may still apply after that window closes.',answer:'For a return filed on time, HMRC generally has until 12 months after the return was delivered to give notice of enquiry. Different rules can apply to late returns and amendments. After the ordinary window closes, HMRC may still consider discovery powers where the statutory conditions and assessment time limits are met.',why:['The enquiry window and the time limit for a discovery assessment are different concepts. A closed enquiry window does not automatically prevent HMRC examining every historic issue.','Discovery assessment periods can depend on the tax and alleged behaviour. Careless or deliberate conduct can produce longer periods than an ordinary case.'],steps:['Create a filing chronology','Retain electronic filing receipts','Identify whether the letter is an enquiry or discovery assessment','Check the stated tax year and legal basis','Preserve appeal rights before debating technical validity'],records:['Filed returns','Submission receipts','Amendment history','HMRC notices and envelopes'],pitfalls:['Using the 12-month rule as a universal limit','Ignoring a notice believed to be out of time','Calculating from the tax-year end instead of the relevant filing event'],faqs:[['Can HMRC investigate after 12 months?','It may be able to use other statutory powers if their conditions are satisfied.'],['Does amending a return affect the window?','An amendment can create a separate enquiry opportunity relating to the amendment.']],sources:saSources}),
q({slug:'documents-hmrc-request-self-assessment-enquiry',cluster:'Self Assessment enquiries',hub:'self-assessment-enquiry',question:'What documents can HMRC request in a Self Assessment enquiry?',short:'Documents HMRC may request',description:'Find out which records HMRC may request during a Self Assessment enquiry and how relevance, privacy and statutory information notices affect your response.',answer:'HMRC may ask for information and documents reasonably required to check the tax position, including bank statements, invoices, contracts, property records, mileage evidence and calculations. The proper scope depends on the return, issue, period and whether the request is informal or made through a formal information notice.',why:['A document request should be connected to checking the relevant tax position. Some documents are restricted or protected, and third-party personal data may require careful handling.','A formal Schedule 36 information notice carries legal consequences and may include appeal rights. It should not be treated as an ordinary request.'],steps:['Map each request to the issue under enquiry','Confirm whether the request is informal or statutory','Index and reconcile every document supplied','Explain missing records and reconstruction methods','Use an agreed secure delivery method'],records:['Bank and card statements','Invoices and receipts','Contracts and completion statements','Expense schedules and mileage logs'],pitfalls:['Sending irrelevant personal records without review','Altering originals or recreating evidence silently','Ignoring a formal information notice'],faqs:[['Can HMRC request personal bank statements?','It may request relevant financial records, but scope and proportionality should be assessed in context.'],['What if records are missing?','Explain why, obtain replacements and document any reasonable reconstruction.']],sources:[...saSources,['GOV.UK: HMRC information and inspection powers','https://www.gov.uk/government/collections/hm-revenue-and-customs-compliance-checks-factsheets']]}),
q({slug:'aspect-vs-full-hmrc-enquiry',cluster:'Self Assessment enquiries',hub:'self-assessment-enquiry',question:'What is the difference between an aspect enquiry and a full HMRC enquiry?',short:'Aspect versus full enquiry',description:'Understand the practical difference between an HMRC aspect enquiry and full enquiry and what happens if the scope expands.',answer:'An aspect enquiry focuses on one or more particular entries or risks, while a full enquiry examines the return and underlying records more broadly. These are HMRC working descriptions rather than different statutory enquiry powers, and an enquiry that begins narrowly can expand if new issues arise.',why:['The opening letter and questions are the best guide to current scope. A narrow request about property expenses should not automatically become a review of unrelated affairs without explanation.','New discrepancies can cause HMRC to ask further questions. Clear reconciliations and contextual explanations reduce avoidable scope expansion.'],steps:['Write a one-sentence scope summary','Answer using HMRC’s numbering','Separate relevant documents from background material','Ask HMRC to identify unresolved points','Confirm any agreed narrowing or expansion in writing'],records:['Opening letter','Question schedule','Document index','Chronology of scope changes'],pitfalls:['Assuming “aspect” guarantees a quick conclusion','Answering unrelated matters speculatively','Failing to challenge an unclear expansion professionally'],faqs:[['Can an aspect enquiry become a full enquiry?','HMRC may widen its questions where information raises additional risks.'],['Does “full enquiry” mean fraud?','No. Breadth alone does not establish deliberate behaviour.']],sources:saSources}),
q({slug:'hmrc-self-assessment-closure-notice',cluster:'Self Assessment enquiries',hub:'self-assessment-enquiry',question:'What is an HMRC closure notice and what should you check?',short:'HMRC closure notices',description:'Learn how a closure notice ends a Self Assessment enquiry, what it may amend and what to check before an appeal deadline expires.',answer:'A closure notice formally ends a Self Assessment enquiry and states HMRC’s conclusions. It may confirm no change or amend the return. The notice should be checked immediately because an amendment or conclusion may carry a short appeal deadline.',why:['An informal statement that HMRC has no more questions is not always the statutory closure document. Formal closure gives procedural certainty.','Check the tax, interest, penalty consequences and whether the conclusions reflect the evidence. Penalties may arrive under separate notices.'],steps:['Record the issue and receipt dates','Compare amendments with the filed return','Recalculate tax and interest independently','Identify the appeal instructions','Keep written confirmation of settled issues'],records:['Closure notice','HMRC conclusion letter','Revised computation','Settlement or appeal correspondence'],pitfalls:['Missing the appeal deadline','Assuming closure cancels every related issue','Paying without checking the calculation'],faqs:[['Can I ask for an enquiry to be closed?','A taxpayer may in some circumstances apply to the tribunal for a direction that HMRC close the enquiry.'],['Can HMRC amend the return in the closure notice?','Yes, where its conclusions identify an amendment.']],sources:saSources}),

q({slug:'what-triggers-hmrc-compliance-check',cluster:'HMRC compliance checks',hub:'compliance-check',question:'What triggers an HMRC compliance check?',short:'Compliance-check triggers',description:'Explore common HMRC compliance-check triggers, including data mismatches, unusual returns, repayment claims and sector risks.',answer:'HMRC may open a compliance check after risk analysis identifies a mismatch, unusual pattern, repayment claim, sector risk or third-party information. Some checks may also be selected as part of wider compliance activity. A trigger is not proof that tax is wrong.',why:['HMRC uses information from returns, employers, banks, platforms, other government bodies and international exchanges. It does not normally reveal detailed risk algorithms.','The practical response is to test the return against source evidence rather than invent a theory about selection.'],steps:['Read the scope and tax periods','Reconcile return figures to ledgers and third-party data','Explain genuine anomalies concisely','Correct real errors through the appropriate route','Maintain a single response file'],records:['Tax returns and accounts','Control-account reconciliations','Third-party statements','Prior-year comparison schedules'],pitfalls:['Guessing the trigger in correspondence','Assuming selection proves non-compliance','Giving inconsistent explanations through multiple contacts'],faqs:[['Are compliance checks random?','Selection methods vary and HMRC does not generally disclose detailed risk criteria.'],['Will every check result in extra tax?','No. A check can close without adjustment.']],sources:checkSources}),
q({slug:'can-hmrc-check-business-bank-account',cluster:'HMRC compliance checks',hub:'compliance-check',question:'Can HMRC check a business bank account during a compliance check?',short:'Business bank account checks',description:'Understand when HMRC may examine business bank statements and how to prepare a bank-to-turnover reconciliation.',answer:'HMRC may request business bank statements and related records where they are reasonably required to check turnover, expenses, loans, transfers or another tax position. Businesses should reconcile deposits to declared income and identify non-trading receipts clearly.',why:['Bank deposits do not automatically equal taxable sales. Transfers, capital introduced, loans, refunds and contra entries may require explanation.','HMRC may compare bank activity with VAT returns, accounts, merchant processors and invoices. An unexplained difference often creates further questions.'],steps:['Export complete statements for the relevant period','Prepare a bank-to-turnover reconciliation','Label transfers and non-trading credits','Tie expenses to invoices and business purpose','Explain cash handling and missing records'],records:['Bank statements','Cashbooks and nominal ledgers','Merchant-processor reports','Loan and capital evidence'],pitfalls:['Sending statements without a reconciliation','Counting transfers twice','Using unsupported descriptions for large credits'],faqs:[['Does every credit count as turnover?','No. Its nature must be established from evidence.'],['Can HMRC ask about payment processors?','Yes, where records are relevant to checking sales or receipts.']],sources:checkSources}),
q({slug:'can-hmrc-request-personal-bank-statements',cluster:'HMRC compliance checks',hub:'compliance-check',question:'Can HMRC request personal bank statements in a business tax enquiry?',short:'Personal bank statements',description:'When can HMRC ask for personal bank statements during a business enquiry, and how should relevance and private information be handled?',answer:'HMRC may ask for personal bank statements where they are relevant to checking a tax position—for example, if business receipts may have entered a personal account or drawings and capital introduced cannot be reconciled. A broad request should be examined against its stated purpose and statutory basis.',why:['A limited company and its director are separate, but personal accounts can become relevant when transactions cross that boundary. Sole traders may have even greater overlap.','Private information unrelated to the tax check requires careful handling. Formal notices have specific rules, restrictions and potential appeal rights.'],steps:['Ask HMRC to explain relevance and period','Identify accounts used for business transactions','Prepare a reconciliation before disclosure','Consider redaction only with agreement or advice','Respond to formal notices within the legal process'],records:['Personal statements for relevant accounts','Director loan account','Drawings and capital schedules','Evidence of transfers between accounts'],pitfalls:['Refusing automatically','Disclosing all private accounts without review','Redacting material unilaterally'],faqs:[['Can HMRC see every bank account automatically?','HMRC has information powers and receives financial data in defined circumstances, but the route depends on the case.'],['Can irrelevant transactions be protected?','Scope and handling should be discussed, particularly under a formal notice.']],sources:checkSources}),
q({slug:'can-hmrc-visit-business-premises',cluster:'HMRC compliance checks',hub:'compliance-check',question:'Can HMRC visit your business premises during a compliance check?',short:'HMRC business visits',description:'Learn when HMRC may propose or conduct a business visit, what to ask before it happens and how inspection powers differ from agreed meetings.',answer:'HMRC may request an agreed visit and also has statutory inspection powers in defined circumstances. The letter or notice should be reviewed to determine the legal basis, scope, timing and any restrictions before access is agreed or refused.',why:['A productive visit should have a written agenda and identify the taxes, records, systems and people required.','Business premises, private dwellings and mixed-use areas can be treated differently. Unannounced or statutory visits require urgent specialist consideration.'],steps:['Request the agenda and attendees','Confirm whether attendance is voluntary or statutory','Prepare relevant systems and records','Nominate staff who understand the processes','Keep a detailed note and confirm actions in writing'],records:['Visit letter or inspection notice','Premises plan where relevant','Accounting-system access plan','Meeting note and action list'],pitfalls:['Giving unrestricted system access','Coaching staff to guess answers','Obstructing a lawful inspection without advice'],faqs:[['Can HMRC enter a private home?','Special restrictions apply, and the precise statutory position should be checked.'],['Can my adviser attend?','Usually an adviser can assist with an agreed compliance meeting or visit.']],sources:checkSources}),
q({slug:'how-far-back-hmrc-compliance-check',cluster:'HMRC compliance checks',hub:'compliance-check',question:'How far back can an HMRC compliance check go?',short:'How far back HMRC can check',description:'Understand ordinary enquiry windows and the longer assessment periods that may apply where HMRC alleges careless or deliberate behaviour.',answer:'How far HMRC can go back depends on the tax, statutory power and alleged behaviour. Ordinary enquiry windows may be relatively short, while discovery and assessment rules can permit longer periods where there is careless or deliberate conduct or another statutory condition.',why:['There is no single “HMRC can always go back X years” rule. Income Tax, Corporation Tax, VAT and PAYE can involve different provisions.','The relevant question is not only when HMRC asks for records but whether it can lawfully assess a period and what evidence supports the alleged behaviour.'],steps:['List every period under review','Identify the power cited for each period','Map filing and payment dates','Preserve older records immediately','Challenge assumptions with evidence, not slogans'],records:['Historic returns and accounts','Filing acknowledgements','Retention policies','Evidence of reasonable care'],pitfalls:['Applying one time limit to every tax','Destroying records after receiving notice','Conceding deliberate behaviour through careless wording'],faqs:[['Can HMRC go back 20 years?','Some regimes allow lengthy periods for deliberate conduct, but conditions must be met.'],['What if records were lawfully destroyed?','Explain the retention policy and reconstruct from reliable third-party evidence where possible.']],sources:checkSources}),
q({slug:'how-hmrc-compliance-check-ends',cluster:'HMRC compliance checks',hub:'compliance-check',question:'How does an HMRC compliance check end?',short:'Ending a compliance check',description:'Understand no-change conclusions, assessments, amendments, contract settlements, penalties and formal closure at the end of an HMRC check.',answer:'A compliance check may end with no change, an agreed correction, an assessment or amendment, a contract settlement, or a disputed decision followed by appeal. The formal ending mechanism depends on the tax and type of enquiry.',why:['Before agreeing figures, separate tax, interest and penalties and verify every period. A contract settlement has legal consequences and should not be signed casually.','Ask HMRC to confirm in writing what has closed and whether any matters remain open. Silence is not dependable closure.'],steps:['Request a schedule of proposed adjustments','Recalculate tax and interest','Review behaviour and penalty findings separately','Confirm appeal rights and deadlines','Obtain written closure or settlement terms'],records:['Final position letter','Assessment or closure notice','Penalty explanation','Payment and settlement schedule'],pitfalls:['Agreeing global figures without breakdown','Missing an appeal while negotiating','Assuming payment alone closes the enquiry'],faqs:[['Can a check end with no tax due?','Yes. HMRC may conclude that no adjustment is required.'],['Does closing the tax issue close penalties?','Not necessarily; penalty decisions may be issued separately.']],sources:checkSources}),

q({slug:'hmrc-vat-enquiry-what-to-expect',cluster:'VAT and PAYE enquiries',hub:'vat-paye-enquiry',question:'What happens during an HMRC VAT enquiry?',short:'HMRC VAT enquiry process',description:'A practical guide to VAT compliance checks, records HMRC may inspect, common risk areas, assessments and how to prepare.',answer:'An HMRC VAT enquiry may test sales, input-tax claims, VAT rates, place and time of supply, partial exemption, bad-debt relief or digital records. HMRC commonly reconciles VAT returns to accounts, invoices, bank activity and transaction data.',why:['VAT errors can arise from classification and evidence as well as arithmetic. A valid invoice does not by itself prove business purpose or entitlement.','The opening letter should define periods and records. Complex issues such as land, international services and disaggregation require technical analysis.'],steps:['Reconcile each VAT return to the ledger','Test samples of sales and purchases','Verify VAT invoices and business purpose','Document rate and place-of-supply decisions','Prepare explanations for manual journals'],records:['VAT account and returns','Sales and purchase invoices','Bank and merchant statements','Making Tax Digital records'],pitfalls:['Providing unreconciled transaction dumps','Assuming all overseas supplies are outside scope','Ignoring private-use or partial-exemption adjustments'],faqs:[['Can HMRC inspect digital VAT records?','Yes, relevant digital records may be examined during a check.'],['Can a VAT check result in penalties?','Potentially, depending on errors, behaviour and the applicable regime.']],sources:vatSources}),
q({slug:'what-triggers-hmrc-paye-compliance-check',cluster:'VAT and PAYE enquiries',hub:'vat-paye-enquiry',question:'What triggers an HMRC PAYE compliance check?',short:'PAYE compliance-check triggers',description:'Learn common PAYE enquiry risk areas including payroll mismatches, benefits, expenses, employment status and off-payroll working.',answer:'A PAYE check may follow payroll-reporting mismatches, late or corrected submissions, benefits and expenses, employment-status risks, off-payroll working, construction payments or discrepancies between accounts and payroll.',why:['HMRC may compare Full Payment Submissions, payment records, P11D information, Corporation Tax accounts and worker data.','A worker paid outside payroll is not automatically self-employed. The contractual terms and actual working relationship both matter.'],steps:['Reconcile payroll reports to the ledger and bank','Review worker-status decisions','Match benefits and expenses to reporting','Explain corrections and late submissions','Preserve contracts and working-practice evidence'],records:['FPS and EPS submissions','Payroll reports and payslips','Worker contracts','P11D and expense records'],pitfalls:['Relying only on contract labels','Leaving director payments unreconciled','Treating reimbursements as automatically non-taxable'],faqs:[['Will HMRC interview workers?','It may seek information relevant to employment status or payroll compliance.'],['Can PAYE and NIC both be assessed?','Yes, payroll issues commonly affect Income Tax and National Insurance.']],sources:vatSources}),
q({slug:'hmrc-vat-records-request',cluster:'VAT and PAYE enquiries',hub:'vat-paye-enquiry',question:'What VAT records can HMRC request?',short:'VAT records HMRC may request',description:'Find out which VAT invoices, ledgers, digital records, bank statements and supporting calculations HMRC may request during a check.',answer:'HMRC may request VAT accounts, returns, sales and purchase invoices, credit notes, import and export evidence, bank records, digital links and calculations relevant to checking VAT. Businesses must retain prescribed VAT records for the applicable period.',why:['The evidence required depends on the transaction. Exports, zero-rating, input tax and bad-debt relief each have specific conditions.','Data should reconcile from source transaction through digital records to the submitted VAT return. Gaps and spreadsheet adjustments should be explained.'],steps:['Create a VAT return reconciliation','Index requested invoices','Identify evidence supporting reliefs and rates','Document digital-record flows','Explain missing or corrected documents'],records:['VAT account','Invoices and credit notes','Import and export documents','Partial-exemption calculations'],pitfalls:['Sending duplicate or altered invoices','Failing to evidence zero-rating','Ignoring digital-link questions'],faqs:[['Are bank statements VAT records?','They may be relevant supporting evidence even though they do not replace VAT invoices.'],['What if an invoice is invalid?','Entitlement depends on the facts and rules; obtain advice before assuming input tax is lost or valid.']],sources:vatSources}),
q({slug:'hmrc-employment-status-enquiry-questions',cluster:'VAT and PAYE enquiries',hub:'vat-paye-enquiry',question:'What questions does HMRC ask in an employment status enquiry?',short:'Employment status questions',description:'Prepare for HMRC questions about control, substitution, mutuality, financial risk, integration and actual working practices.',answer:'HMRC employment-status enquiries examine the written contract and the reality of the relationship. Questions commonly cover personal service, substitution, control, payment, financial risk, equipment, integration, other clients and how engagements end.',why:['No single factor normally decides status. The weight of factors depends on the contract and work.','Evidence from the engager and worker should be consistent with actual practice. A substitution clause that cannot realistically operate may carry limited weight.'],steps:['Map the contractual terms','Interview operational managers and workers','Collect examples of actual control and substitution','Document equipment and financial risk','Review status for each distinct engagement'],records:['Contracts and variations','Invoices and payment schedules','Work instructions and rotas','Status assessment records'],pitfalls:['Using generic self-employed templates','Answering only from HR rather than operations','Assuming Companies House incorporation decides status'],faqs:[['Does a personal service company guarantee off-payroll treatment?','No. Separate off-payroll rules and the underlying engagement must be considered.'],['Is CEST determinative?','HMRC provides CEST, but the accuracy of inputs and full legal analysis remain important.']],sources:[...vatSources,['GOV.UK: Employment status','https://www.gov.uk/employment-status']]}),
q({slug:'hmrc-benefits-expenses-paye-enquiry',cluster:'VAT and PAYE enquiries',hub:'vat-paye-enquiry',question:'How does HMRC check employee benefits and expenses?',short:'Benefits and expenses checks',description:'Understand HMRC checks into company cars, medical cover, travel, subsistence, reimbursed expenses and PAYE Settlement Agreements.',answer:'HMRC may reconcile benefits and expenses to payroll, P11Ds, PAYE Settlement Agreements, expense systems, accounts and supporting receipts. It will test exemptions, business purpose, valuation and whether items should have been payrolled or reported.',why:['An expense being commercially incurred does not automatically make it exempt for employment-tax purposes. Travel and subsistence depend on workplace and journey rules.','Director and employee personal expenditure posted through company accounts is a frequent risk area.'],steps:['Reconcile benefit accounts to P11Ds and payroll','Review expense categories and policies','Test permanent and temporary workplace treatment','Identify personal expenditure and reimbursements','Correct reporting through the appropriate process'],records:['P11Ds and PSA calculations','Expense claims and receipts','Vehicle records','Company card statements'],pitfalls:['Confusing Corporation Tax deductibility with PAYE exemption','Ignoring benefits for family members','Using round-sum allowances without checking rules'],faqs:[['Can benefits be payrolled?','Some benefits can be processed through payroll under the applicable rules and registration requirements.'],['Does a receipt prove an expense is tax-free?','No. The employment-tax conditions still need to be met.']],sources:vatSources}),
q({slug:'hmrc-cis-paye-compliance-check',cluster:'VAT and PAYE enquiries',hub:'vat-paye-enquiry',question:'What happens in an HMRC CIS and PAYE compliance check?',short:'CIS and PAYE checks',description:'Learn how HMRC checks contractor status, subcontractor verification, deductions, returns, payroll and gross-payment treatment.',answer:'A CIS and PAYE check may test whether workers and subcontractors were classified correctly, verified, paid under the correct deduction rate and reported accurately. HMRC may also consider whether payments actually belonged in PAYE.',why:['CIS does not decide employment status. A worker can fall outside employment in one engagement but not another, and the facts must be examined.','Contractors should reconcile CIS returns, deduction statements, invoices, bank payments and ledgers.'],steps:['List every labour supplier and worker','Reconcile CIS returns to payments','Check verification evidence and deduction rates','Review employment status separately','Correct missing statements or returns transparently'],records:['Subcontractor verifications','Monthly CIS returns','Payment and deduction statements','Contracts and invoices'],pitfalls:['Assuming a UTR proves self-employment','Netting materials without evidence','Failing to reconcile CIS suffered or deducted'],faqs:[['Is CIS the same as PAYE?','No. CIS is a deduction regime and does not replace employment-status analysis.'],['Can HMRC cancel gross payment status?','Compliance failures can affect gross-payment treatment under the applicable rules.']],sources:[...vatSources,['GOV.UK: Construction Industry Scheme','https://www.gov.uk/what-is-the-construction-industry-scheme']]}),

q({slug:'what-is-cop8-hmrc-investigation',cluster:'COP8 and COP9 investigations',hub:'cop8-cop9-investigation',question:'What is an HMRC Code of Practice 8 investigation?',short:'COP8 investigations',description:'Understand COP8 investigations into complex tax avoidance, the opening letter, information requests, meetings and possible outcomes.',answer:'Code of Practice 8 is HMRC’s civil investigation procedure for cases where it suspects a significant loss of tax involving complex arrangements or avoidance. It is not itself a criminal investigation, but the issues and potential exposure can be serious.',why:['COP8 cases are handled by HMRC’s Fraud Investigation Service and may involve multiple entities, transactions and technical provisions.','The code explains HMRC’s approach and taxpayer rights. The opening letter should be reviewed before substantive explanations are offered.'],steps:['Preserve the complete opening pack','Identify every taxpayer, entity and period','Build a transaction chronology','Coordinate legal and tax advice','Control all communications through an agreed team'],records:['COP8 letter and code','Scheme and transaction documents','Tax opinions and implementation records','Returns and computations'],pitfalls:['Treating COP8 as a routine enquiry','Assuming advice automatically makes treatment correct','Giving fragmented explanations before establishing facts'],faqs:[['Is COP8 a criminal investigation?','COP8 is a civil investigation code, although HMRC may change approach if evidence of fraud emerges.'],['Should I attend a meeting alone?','Specialist advice before any meeting is strongly advisable.']],sources:copSources}),
q({slug:'what-is-cop9-contractual-disclosure-facility',cluster:'COP8 and COP9 investigations',hub:'cop8-cop9-investigation',question:'What is COP9 and the Contractual Disclosure Facility?',short:'COP9 and the CDF',description:'A careful guide to HMRC COP9, suspected tax fraud, the Contractual Disclosure Facility, outline disclosure and the need for specialist advice.',answer:'Under Code of Practice 9, HMRC offers the Contractual Disclosure Facility when it suspects tax fraud. The recipient can admit deliberate conduct and make a complete disclosure under the contractual process, or deny fraud. The decision has serious legal consequences.',why:['The CDF offer, acceptance deadline and outline disclosure must be handled precisely. Contractual protection depends on truthful and complete disclosure of admitted tax fraud within the terms.','COP9 is not a conviction, but careless wording, partial admissions or incomplete disclosure can materially increase risk. Independent specialist and legal advice is normally essential.'],steps:['Do not respond substantively before obtaining advice','Secure all records and communications','Map every tax, entity and period potentially affected','Decide the CDF response on complete facts','Prepare any outline disclosure carefully and consistently'],records:['COP9 opening letter','CDF offer and forms','Historic returns and accounts','Personal and business financial records'],pitfalls:['Missing the stated deadline','Making a partial or tactical admission','Destroying or editing records'],faqs:[['Does COP9 mean I have been convicted?','No. It means HMRC suspects tax fraud and has offered its civil contractual process.'],['Does accepting the CDF guarantee immunity for everything?','Protection is governed by the precise contractual terms and complete disclosure of admitted conduct.']],sources:copSources}),
q({slug:'cop8-vs-cop9-difference',cluster:'COP8 and COP9 investigations',hub:'cop8-cop9-investigation',question:'What is the difference between COP8 and COP9?',short:'COP8 versus COP9',description:'Compare HMRC Code of Practice 8 and Code of Practice 9, including avoidance, suspected fraud, disclosure decisions and risk.',answer:'COP8 generally concerns significant tax loss involving complex arrangements or avoidance, while COP9 is used where HMRC suspects tax fraud and offers the Contractual Disclosure Facility. Both are civil procedures, but COP9 directly raises suspected deliberate conduct and contractual disclosure choices.',why:['The label affects strategy, risk and the kind of advice needed. Neither process should be approached as ordinary correspondence.','A case can change direction if HMRC’s understanding of behaviour changes. Complete facts and consistent communications are therefore essential.'],steps:['Identify which code and documents were issued','Compare alleged issues with filed returns','Assess behaviour separately from technical tax treatment','Coordinate advisers and privilege where appropriate','Plan disclosure and correspondence centrally'],records:['Opening code and letters','Tax planning documents','Advice and implementation evidence','Disclosure chronology'],pitfalls:['Using COP8 and COP9 interchangeably','Assuming a technical argument eliminates conduct risk','Allowing multiple representatives to send inconsistent accounts'],faqs:[['Can COP8 become COP9?','HMRC may change its approach where evidence alters its view of suspected conduct.'],['Are both handled by specialist HMRC teams?','They are associated with HMRC’s Fraud Investigation Service.']],sources:copSources}),
q({slug:'what-questions-hmrc-ask-cop9',cluster:'COP8 and COP9 investigations',hub:'cop8-cop9-investigation',question:'What questions may HMRC ask during a COP9 investigation?',short:'COP9 investigation questions',description:'Prepare for COP9 questions about deliberate conduct, entities, bank accounts, beneficial ownership, offshore matters and disclosure completeness.',answer:'COP9 questions can cover what was done, who was involved, what the taxpayer knew, why returns were submitted as they were, which taxes and periods are affected, where funds or assets are held and whether the outline disclosure is complete.',why:['HMRC is examining conduct as well as calculations. Emails, advice, banking flows and inconsistent explanations may be relevant.','A meeting is not the place to reconstruct complex events from memory. Establish a verified chronology and identify matters that require checking.'],steps:['Build a privileged factual chronology where appropriate','Identify decision-makers and advisers','Trace funds and beneficial ownership','Separate known facts from matters still being verified','Prepare for meetings with a written agenda'],records:['Emails and correspondence','Banking and asset schedules','Board and trust records','Tax advice and filings'],pitfalls:['Guessing dates or motives','Minimising facts that documents later reveal','Answering beyond the agreed scope without preparation'],faqs:[['Must I attend a COP9 meeting?','The legal and strategic position depends on the request; obtain specialist advice.'],['Can HMRC ask about overseas assets?','Yes, where relevant to the suspected tax loss and disclosure.']],sources:copSources}),
q({slug:'cop9-outline-disclosure-what-include',cluster:'COP8 and COP9 investigations',hub:'cop8-cop9-investigation',question:'What should a COP9 outline disclosure include?',short:'COP9 outline disclosure',description:'Understand the purpose of the COP9 outline disclosure, deliberate conduct admissions, entities, taxes, periods and supporting narrative.',answer:'An outline disclosure should identify the deliberate conduct being admitted and give sufficient information about the entities, taxes, periods, arrangements and amounts involved, following the CDF documentation. It is not a casual summary and must be truthful and complete as an outline.',why:['The outline frames the investigation and the contractual position. Omitting known deliberate conduct can undermine protection and credibility.','It should distinguish admitted fraud from errors or technical positions not admitted as deliberate, using careful language supported by facts.'],steps:['Review the current CDF forms and deadline','Map all deliberate conduct considered for admission','Identify connected entities and taxes','Explain mechanism and knowledge clearly','Have specialist legal and tax review before submission'],records:['CDF forms','Conduct chronology','Entity and tax-period matrix','Initial tax-loss estimates'],pitfalls:['Treating “outline” as permission to omit known conduct','Using vague labels without mechanism','Submitting before the wider factual scope is understood'],faqs:[['Must exact figures be available immediately?','The process may allow later detailed quantification, but the known conduct and scope must be addressed accurately.'],['Can an outline be amended?','Any correction requires urgent specialist advice and full transparency.']],sources:copSources}),
q({slug:'can-cop9-lead-criminal-prosecution',cluster:'COP8 and COP9 investigations',hub:'cop8-cop9-investigation',question:'Can a COP9 investigation lead to criminal prosecution?',short:'COP9 and prosecution risk',description:'Understand the relationship between COP9, the CDF, complete disclosure and circumstances that may create criminal investigation risk.',answer:'COP9 is a civil investigation route. The CDF contains important assurances concerning conduct fully disclosed and admitted under its terms, but it is not a blanket protection for false statements, incomplete disclosure or separate offences. Criminal risk requires specialist legal advice.',why:['HMRC publishes both civil investigation and criminal investigation policies. The contractual wording, conduct disclosed and taxpayer cooperation matter.','Trying to manage perceived prosecution risk through partial truth is dangerous. The correct approach is confidential advice and complete factual analysis.'],steps:['Obtain independent specialist and legal advice immediately','Preserve all potentially relevant evidence','Do not make misleading statements','Understand the precise CDF contractual terms','Ensure every submission is verified and consistent'],records:['COP9 and CDF documents','Legal advice records','Complete disclosure file','Evidence-preservation log'],pitfalls:['Assuming COP9 is already a prosecution','Assuming acceptance protects undisclosed conduct','Discussing the case casually in unprotected communications'],faqs:[['Is COP9 a criminal charge?','No. It is a civil investigation process used where HMRC suspects fraud.'],['Can false disclosure worsen risk?','Yes. Deliberately false or incomplete statements can have serious consequences.']],sources:copSources}),

q({slug:'how-hmrc-finds-undeclared-income',cluster:'Undeclared income and disclosures',hub:'undeclared-income-disclosure',question:'How does HMRC find undeclared income?',short:'How HMRC finds undeclared income',description:'Learn how HMRC may identify undeclared income through returns, banks, employers, property, online platforms and international data.',answer:'HMRC can identify undeclared income by comparing tax returns with information from employers, financial institutions, property records, online platforms, other government bodies, overseas tax authorities and previous enquiries. A mismatch may lead to a nudge letter, compliance check or investigation.',why:['Third-party data can be incomplete, duplicated or allocated to the wrong person or period. It should be reconciled rather than automatically accepted or dismissed.','If an omission exists, the route and timing of disclosure affect how HMRC treats cooperation and may influence penalties.'],steps:['Identify every income source and tax year','Obtain third-party statements','Reconcile gross receipts, allowable costs and tax already paid','Choose the correct disclosure route','Submit complete calculations and supporting explanations'],records:['Bank and platform statements','Property completion records','Employment and pension documents','Foreign income and tax certificates'],pitfalls:['Disclosing only the item HMRC mentioned','Confusing sales proceeds with taxable profit','Waiting for HMRC to calculate everything'],faqs:[['Does HMRC receive online-platform data?','Platforms may have reporting obligations and HMRC can obtain information through statutory and international mechanisms.'],['Can HMRC data be wrong?','Yes, so it should be checked against source evidence.']],sources:disclosureSources}),
q({slug:'forgot-declare-rental-income-hmrc',cluster:'Undeclared income and disclosures',hub:'undeclared-income-disclosure',question:'What should I do if I forgot to declare rental income?',short:'Forgotten rental income',description:'Steps for disclosing undeclared UK property income, reconstructing rent and expenses, using the Let Property Campaign and calculating tax.',answer:'If UK residential property income was omitted, identify every affected year, reconstruct rents and allowable expenses, calculate the tax, interest and potential penalties, and use the disclosure route appropriate to your circumstances. HMRC’s Let Property Campaign may be relevant for eligible landlords.',why:['Rental profit is not simply rent received: allowable expenses, ownership, finance-cost rules and periods of private use can affect the calculation.','A disclosure should normally cover the complete position, not only the latest year. Joint ownership and overseas property require additional analysis.'],steps:['List properties, ownership and letting periods','Reconstruct rent received by tax year','Review allowable expenses and finance costs','Check prior returns and assessment time limits','Notify and disclose through the correct HMRC route'],records:['Tenancy agreements','Agent statements and bank deposits','Mortgage interest certificates','Repairs and management invoices'],pitfalls:['Claiming capital improvements as repairs','Ignoring jointly owned income','Using mortgage payments rather than applicable finance costs'],faqs:[['Is the Let Property Campaign always available?','Eligibility depends on the taxpayer and property circumstances; check current HMRC guidance.'],['Should I wait for HMRC to contact me?','HMRC advises taxpayers to disclose unpaid tax as soon as possible.']],sources:[...disclosureSources,['GOV.UK: Let Property Campaign','https://www.gov.uk/government/publications/let-property-campaign-your-guide-to-making-a-disclosure']]}),
q({slug:'disclose-undeclared-foreign-income-hmrc',cluster:'Undeclared income and disclosures',hub:'undeclared-income-disclosure',question:'How do I disclose undeclared foreign income to HMRC?',short:'Foreign income disclosure',description:'A guide to disclosing foreign bank interest, dividends, pensions, property income and gains through the appropriate HMRC route.',answer:'Start by establishing UK residence, the source and ownership of each item, the affected years, foreign tax paid and the applicable UK rules. The Worldwide Disclosure Facility may be relevant where offshore income or gains have produced a UK tax liability.',why:['Foreign tax paid does not automatically eliminate UK reporting. Double-taxation relief, exchange rates and treaty treatment require calculation.','Offshore assessment and penalty rules can differ from domestic cases, and international data exchange means incomplete disclosure is especially risky.'],steps:['Determine residence and relevant tax status for each year','Inventory overseas accounts, assets and income','Translate statements and calculate sterling amounts','Claim appropriate foreign-tax credit relief','Use the correct disclosure service and meet its deadlines'],records:['Foreign bank and broker statements','Overseas property accounts','Foreign returns and tax certificates','Residence and travel records'],pitfalls:['Assuming overseas withholding settles UK tax','Ignoring gains or remittances','Converting only net receipts without methodology'],faqs:[['What is the Worldwide Disclosure Facility?','It is an HMRC route for disclosing UK tax liabilities relating wholly or partly to offshore matters.'],['Can old offshore years still be assessable?','Potentially, depending on the statutory rules and behaviour.']],sources:[...disclosureSources,['GOV.UK: Worldwide Disclosure Facility','https://www.gov.uk/guidance/worldwide-disclosure-facility-make-a-disclosure']]}),
q({slug:'prompted-vs-unprompted-hmrc-disclosure',cluster:'Undeclared income and disclosures',hub:'undeclared-income-disclosure',question:'What is the difference between a prompted and unprompted disclosure?',short:'Prompted versus unprompted disclosure',description:'Understand when HMRC treats a disclosure as prompted or unprompted and why timing may affect penalty ranges and mitigation.',answer:'Broadly, an unprompted disclosure is made when the taxpayer has no reason to believe HMRC has discovered or is about to discover the issue. A prompted disclosure follows HMRC contact or circumstances giving that expectation. The statutory test and facts determine the classification.',why:['Calling a disclosure voluntary does not make it legally unprompted. A nudge letter, enquiry or known data match may be relevant.','Prompted disclosures can still receive penalty mitigation through telling, helping and giving access, so completeness and cooperation remain important.'],steps:['Record when the issue was first identified','Preserve all HMRC contact and envelopes','Take advice before notifying partial figures','Prepare a complete conduct chronology','Document telling, helping and access provided'],records:['HMRC letters','Internal discovery notes','Adviser correspondence','Disclosure timetable'],pitfalls:['Backdating awareness','Delaying notification while perfecting figures','Assuming prompted means mitigation is impossible'],faqs:[['Does an HMRC nudge letter make disclosure prompted?','It may affect the analysis depending on its content and the facts.'],['Why does classification matter?','Penalty ranges and minimums can differ under applicable regimes.']],sources:disclosureSources}),
q({slug:'hmrc-digital-disclosure-service-which-route',cluster:'Undeclared income and disclosures',hub:'undeclared-income-disclosure',question:'Which HMRC disclosure service should I use?',short:'Choosing an HMRC disclosure route',description:'Compare common HMRC disclosure routes for rental income, offshore matters, cryptoassets and other undeclared income.',answer:'The appropriate route depends on the tax, income source, offshore connection, whether HMRC has already opened an enquiry and whether deliberate conduct is involved. Options may include a named campaign, the Digital Disclosure Service, Worldwide Disclosure Facility, cryptoasset disclosure service, return amendment or disclosure within an open enquiry.',why:['Using the wrong portal can delay resolution or omit taxes the service does not cover. Some routes require notification followed by a fixed disclosure deadline.','COP9 should not be self-selected as an ordinary disclosure campaign; it is offered by HMRC where it suspects fraud.'],steps:['Map all taxes, sources and years','Check whether any return can still be amended','Identify open enquiries or HMRC contact','Read current eligibility and excluded taxes','Coordinate all routes so the disclosure is complete'],records:['Tax and year matrix','Copies of filed returns','HMRC contact history','Calculations by disclosure route'],pitfalls:['Using separate routes without reconciling totals','Missing the post-notification deadline','Assuming one service covers every tax'],faqs:[['Can I amend a recent return instead?','Often a return can be amended within its statutory amendment window, but wider omissions may require another route.'],['Is there a cryptoasset disclosure service?','HMRC provides a service for unpaid tax relating to cryptoassets; eligibility and taxes must be checked.']],sources:disclosureSources}),
q({slug:'can-voluntary-disclosure-prevent-prosecution',cluster:'Undeclared income and disclosures',hub:'undeclared-income-disclosure',question:'Can a voluntary disclosure to HMRC prevent prosecution?',short:'Disclosure and prosecution risk',description:'Understand what voluntary disclosure can and cannot do where undeclared tax, deliberate conduct or suspected fraud may be involved.',answer:'An ordinary voluntary disclosure does not provide a general guarantee against criminal investigation or prosecution. Early, complete and accurate disclosure can be highly relevant to HMRC’s response and penalties, but serious deliberate conduct requires specialist legal and tax advice.',why:['HMRC publishes policies governing civil and criminal responses. The amount, conduct, evidence, cooperation and public-interest factors can matter.','The COP9 Contractual Disclosure Facility has specific terms when offered by HMRC, but it is not the same as an ordinary Digital Disclosure Service submission.'],steps:['Obtain confidential specialist advice before contact','Preserve all records','Establish the complete scope of conduct and tax','Avoid false reassurance or partial admissions','Use the correct route with verified disclosure'],records:['Conduct chronology','Complete tax-loss schedule','HMRC correspondence','Evidence-preservation record'],pitfalls:['Assuming payment removes criminal risk','Making an incomplete disclosure to test HMRC’s reaction','Destroying embarrassing documents'],faqs:[['Does paying tax guarantee no prosecution?','No. Payment and conduct are separate considerations.'],['Should deliberate omissions be handled without advice?','Specialist legal and tax advice is strongly recommended.']],sources:disclosureSources}),

q({slug:'how-to-appeal-hmrc-penalty',cluster:'HMRC penalties and appeals',hub:'penalties-and-tax-appeals',question:'How do I appeal an HMRC penalty?',short:'Appealing an HMRC penalty',description:'A step-by-step guide to identifying the penalty, protecting the usual 30-day deadline, drafting grounds and submitting evidence.',answer:'Use the appeal instructions on the penalty notice, normally within the stated deadline—often 30 days. Identify the precise decision, explain why it is wrong, state the result sought and provide supporting evidence. Different penalties and taxes have different routes.',why:['An appeal challenges the legal correctness of a decision; a complaint challenges service. Sending only a complaint may not preserve appeal rights.','Grounds may involve reasonable excuse, incorrect facts, incorrect calculation, statutory conditions or penalty behaviour and mitigation.'],steps:['Record the decision and deadline','Identify the statutory appeal route','Submit protective grounds if evidence is still being gathered','Attach an indexed evidence schedule','Keep proof of submission and acknowledgement'],records:['Penalty notice','Filed returns and receipts','Chronology and supporting evidence','Alternative calculation'],pitfalls:['Waiting for a telephone callback past the deadline','Appealing the tax but not the separate penalty','Using generic hardship wording as grounds'],faqs:[['Can I appeal online?','Some penalties have an online route; follow the exact notice and GOV.UK service.'],['Must I pay before appealing?','Payment rules differ by tax and decision; check the notice and obtain advice.']],sources:appealSources}),
q({slug:'hmrc-appeal-30-day-deadline',cluster:'HMRC penalties and appeals',hub:'penalties-and-tax-appeals',question:'What is the HMRC appeal deadline and when does the 30-day period start?',short:'HMRC appeal deadlines',description:'Understand the usual 30-day HMRC appeal period, how to protect a deadline and what to do when a decision arrives late.',answer:'Many HMRC appeal routes require action within 30 days of the decision or notification, but the exact starting point and procedure depend on the tax and notice. Read the document immediately and do not assume negotiations extend the deadline.',why:['Direct-tax and indirect-tax procedures differ, and a statutory review can create a further deadline. Tribunal notification also has its own rules.','If time is short, a concise protective appeal can preserve the position while detailed evidence is assembled.'],steps:['Save the letter and envelope or electronic notice','Calculate the deadline conservatively','Submit through the specified channel','Request written acknowledgement','Diary review and tribunal deadlines separately'],records:['Decision letter','Evidence of receipt','Appeal submission receipt','Review correspondence'],pitfalls:['Calculating from when an adviser opened the letter','Assuming HMRC silence extends time','Missing a second deadline after review'],faqs:[['Is every appeal deadline 30 days?','No. Thirty days is common, but the governing notice and legislation control.'],['What if the letter arrived late?','Act immediately and explain the delivery facts with evidence.']],sources:appealSources}),
q({slug:'what-counts-reasonable-excuse-hmrc',cluster:'HMRC penalties and appeals',hub:'penalties-and-tax-appeals',question:'What counts as a reasonable excuse for an HMRC penalty?',short:'HMRC reasonable excuse',description:'Learn how HMRC and tribunals assess reasonable excuse and what evidence can support illness, bereavement, system failure or other events.',answer:'A reasonable excuse is assessed in light of the taxpayer’s circumstances and the obligation missed. The taxpayer should show what prevented compliance, why the response was reasonable and that the failure was remedied without unreasonable delay after the excuse ended.',why:['A label such as illness or computer failure is not enough. Dates, severity, attempts to comply, alternatives and remedial action matter.','Reliance on another person, lack of funds or misunderstanding may be treated differently depending on the legislation and full facts.'],steps:['Build a date-by-date chronology','Connect the event directly to the missed obligation','Collect independent evidence','Explain attempts and alternatives','Show prompt remedy after the obstacle ended'],records:['Medical or bereavement evidence','System status and support records','Correspondence with advisers','Filing and payment receipts'],pitfalls:['Copying a generic excuse template','Omitting the period after the event ended','Exaggerating evidence'],faqs:[['Is illness always a reasonable excuse?','No. Its timing, impact and the taxpayer’s actions must be considered.'],['Can reliance on an accountant qualify?','The legal treatment is fact-specific and using an adviser does not automatically remove responsibility.']],sources:appealSources}),
q({slug:'hmrc-statutory-review-vs-tribunal',cluster:'HMRC penalties and appeals',hub:'penalties-and-tax-appeals',question:'Should I accept an HMRC statutory review or appeal to the tax tribunal?',short:'Statutory review versus tribunal',description:'Compare HMRC statutory review with First-tier Tribunal proceedings, including independence, evidence, timing, cost and strategy.',answer:'A statutory review is an internal review by an HMRC officer not previously involved in the decision. The First-tier Tribunal is independent of HMRC. The better route depends on the decision, legal issues, evidence, cost, timing and whether further discussion may resolve the dispute.',why:['A review can be quicker and less formal, but it remains within HMRC. A tribunal provides independent determination with procedural obligations and litigation risk.','Choosing or completing a review affects the deadline for tribunal notification. Every date must be diarised.'],steps:['Assess the strength and type of dispute','Check available review and tribunal rights','Preserve the current deadline','Prepare the same disciplined evidence file for either route','Consider costs, publicity and settlement options'],records:['Decision and appeal','Review offer','Evidence bundle','Legal issue and remedy summary'],pitfalls:['Accepting review without preparing evidence','Missing tribunal notification after the review conclusion','Assuming tribunal is automatically expensive or automatically better'],faqs:[['Who conducts the statutory review?','An HMRC officer who was not involved in the original decision.'],['Is the tribunal part of HMRC?','No. The First-tier Tribunal is independent.']],sources:appealSources}),
q({slug:'late-hmrc-appeal-what-to-do',cluster:'HMRC penalties and appeals',hub:'penalties-and-tax-appeals',question:'Can I make a late appeal against an HMRC decision?',short:'Late HMRC appeals',description:'What to do after missing an HMRC appeal deadline, including explaining delay, submitting grounds and seeking permission.',answer:'HMRC or the tribunal may permit a late appeal, but permission is not automatic. Submit the appeal promptly, explain the entire period of delay, provide evidence and include the substantive grounds against the decision.',why:['The length of delay, reasons, promptness after the obstacle ended, merits and prejudice may be relevant depending on the decision-maker and case law.','Continuing delay while perfecting the application makes the position harder. Act first, then supplement responsibly.'],steps:['Submit the appeal immediately','Explain each period of delay','Attach supporting evidence','Set out the underlying grounds clearly','Request confirmation of whether lateness is accepted'],records:['Original decision','Chronology of delay','Medical, delivery or system evidence','Substantive appeal documents'],pitfalls:['Explaining only the first few days of delay','Blaming an adviser without evidence','Submitting a lateness explanation but no actual appeal'],faqs:[['Is a late appeal automatically rejected?','No, but permission depends on the facts and applicable test.'],['Does a strong underlying case excuse delay?','Merits may be relevant, but they do not remove the need to explain lateness.']],sources:appealSources}),
q({slug:'hmrc-rejected-appeal-next-steps',cluster:'HMRC penalties and appeals',hub:'penalties-and-tax-appeals',question:'HMRC rejected my appeal—what can I do next?',short:'After HMRC rejects an appeal',description:'Options after HMRC rejects a tax or penalty appeal, including statutory review, tribunal notification, ADR and payment considerations.',answer:'The decision letter should explain whether you can accept a statutory review, notify the First-tier Tribunal or take another step. Deadlines are commonly short. Alternative dispute resolution may help some cases but does not itself preserve appeal rights.',why:['Review, tribunal and ADR serve different purposes. A complaint is not a substitute for challenging the substantive decision.','Collection and interest may continue depending on the tax, even while the dispute proceeds. Consider postponement, hardship or Time to Pay where applicable.'],steps:['Record the new decision date and deadline','Read every available option','Preserve tribunal rights before pursuing informal resolution','Update grounds and evidence','Address payment separately from correctness'],records:['Appeal rejection','Review offer','Current tax statement','Complete appeal bundle'],pitfalls:['Continuing correspondence past the tribunal deadline','Assuming ADR suspends time','Ignoring collection notices'],faqs:[['Can I go straight to tribunal?','The route depends on the tax and procedural stage; follow the decision notice.'],['Can I complain instead?','A complaint concerns service and usually does not replace an appeal against the tax decision.']],sources:appealSources}),
];

